INSERT INTO `v1_8b3971aac2c3b3fa0bcb28b4a1533b48508641ba40750c7ef4c2e93bfa8bf98d` VALUES (13, "水属性ボーナスアップ", 1, "水属性のキャラが４体以上編成されているとき、キャラの属性ボーナスが強化される。水属性と風属性以外の属性ボーナスを無効化する。", 10101);
